// Precompute: last occurrence of each character in pattern
int lastOcc[ALPHABET_SIZE];
for (int c = 0; c < ALPHABET_SIZE; c++)
  lastOcc[c] = -1;  // not in pattern
for (int j = 0; j < m; j++)
  lastOcc[P[j]] = j;  // rightmost occurrence

// Bad character shift at position k:
// shift = k - lastOcc[T[i+k]]  (if > 0, else 1)

// gs[k] = shift when mismatch occurs at P[k], so the matched
//         good suffix is G = P[k+1..m-1] (length L = m-1-k).

for k = 0 to m-1:
  L = m - 1 - k
  G = P[k+1..m-1]             // the matched suffix (empty if k = m-1)

  // Special case: rightmost mismatch (G empty). No matched suffix to
  // leverage, so fall back on the bad-character rule — convention: 1.
  if k == m-1:
    gs[k] = 1
    continue

  gs[k] = m                   // default: shift past the whole pattern

  // --- Case 1: G reappears in P at an earlier alignment, with the
  //     preceding character different from P[k]. Scan j = k..0 so that
  //     an occurrence of G aligned at the very start of P (j = k,
  //     j-L = -1, "no previous char") is considered too.
  for j = k down to 0:
    // Is P[j-L+1 .. j] == G  and  P[j-L] != P[k] ?
    if j-L+1 >= 0 and P[j-L+1 .. j] == G and (j-L < 0 or P[j-L] != P[k]):
      gs[k] = (k+1) - (j-L+1) // shift so that occurrence aligns under G
      break

  if gs[k] < m: continue       // Case 1 found, done

  // --- Case 2: only a proper prefix of P matches a suffix of G ---
  for len = L-1 down to 1:
    if P[0..len-1] == G[L-len..L-1]:   // prefix of P == suffix of G
      gs[k] = m - len
      break
  // else gs[k] stays m (shift whole pattern)

// Convert string to number (Horner's rule)
f(S) {
  result = 0
  for i = 0 to m-1:
    result = result * |Σ| + S[i]
  return result
}
// Example: f("BABX") = 1·26³ + 0·26² + 1·26 + 23 = 17625

// Rabin-Karp with modular hashing
q = prime_number
h = |Σ|^(m-1) mod q             // precomputed high-order coefficient
x = hash(P[0..m-1]) mod q
y = hash(T[0..m-1]) mod q

for i = 0 to n-m:
  if y == x:
    if P[0..m-1] == T[i..i+m-1]:   // verify (avoid false positives)
      return i
  // Skip the rolling update on the final window — T[i+m] would read past the end.
  if i < n-m:
    // Add + q to keep the intermediate non-negative under C-style mod:
    y = (((y - T[i] * h) mod q + q) * |Σ| + T[i+m]) mod q

return -1
